@dataclass
class ColumnRef(Expression):
    """Reference to a column, optionally qualified by table."""

    name: str
    table: str | None = None

    @property
    def qualified_name(self) -> str:
        if self.table:
            return f"{self.table}.{self.name}"
        return self.name


